// src/api/apiService.ts
import axios, {
  AxiosError,
  AxiosHeaders,
  AxiosResponse,
  InternalAxiosRequestConfig,
} from "axios";
import { AUTH_URL } from "@/app/api/Config";
import { tokenManager } from "../api/TokenManager";
import { getCookie, setCookie } from "./clientCookieUtils";
import { toast } from "react-toastify";

export enum Status {
  SUCCESS = "Success",
  FAILED = "Failed",
}

// Base Axios instance with default headers
const apiClient = axios.create({
  headers: {
    api_version: "v1",
    "Content-Type": "application/json",
  },
});

// Axios request interceptor to add access token
apiClient.interceptors.request.use(
  (config) => {
    const accessToken = tokenManager.getToken();
    if (accessToken) {
      config.headers["Authorization"] = `Bearer ${accessToken}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  },
);

interface CustomAxiosRequestConfig extends InternalAxiosRequestConfig {
  _retry?: boolean;
}

// Axios response interceptor to handle 401 errors
apiClient.interceptors.response.use(
  (response) => response,
  async (error: AxiosError) => {
    const originalRequest = error.config as CustomAxiosRequestConfig;
    console.log(error);
    if (
      originalRequest &&
      error.response?.status === 401 &&
      !originalRequest._retry
    ) {
      originalRequest._retry = true;

      const newAccessToken = await refreshAccessToken();
      if (newAccessToken) {
        tokenManager.setToken(newAccessToken);

        if (!originalRequest.headers) {
          originalRequest.headers = new AxiosHeaders();
        }
        originalRequest.headers.set(
          "Authorization",
          `Bearer ${newAccessToken}`,
        );

        return apiClient.request(originalRequest);
      } else {
        // Redirect to login without UI-specific code
        tokenManager.clearRefreshToken();
        tokenManager.clearToken();
        window.location.href = "/login";
        return Promise.reject(
          new Error("Session expired. Please log in again."),
        );
      }
    }
    return Promise.reject(error);
  },
);

const apiClientNoIntercep = axios.create({
  headers: {
    api_version: "v1",
    "Content-Type": "application/json",
  },
});

export const refreshAccessToken = async (): Promise<string | null> => {
  try {
    const baseAuthUrl = (process.env.NEXT_PUBLIC_AUTH_URL || AUTH_URL).replace(/\/$/, "");
    const response = await axios.post(
      `${baseAuthUrl}/refresh_token/`,
      { session_id: getCookie("sessionId") },
      {
        headers: {
          api_version: "v1",
          "Content-Type": "application/json",
        },
        // withCredentials: true, // Ensures cookies are sent with the request
      },
    );

    const newAccessToken = response.data.access_token;
    if (response.data.refresh_token) {
      setCookie("nd-refreshToken", response.data.refresh_token, 0.5);
    }

    tokenManager.setToken(newAccessToken);
    return newAccessToken;
  } catch (error) {
    console.error("Error refreshing access token:", error);
    return null; // Return null if refresh fails
  }
};

// API service functions
export const postRequest = async <T>(
  url: string,
  data: any,
  headers?: any,
  withCredentials: boolean = false,
  useInterceptor: boolean = true,
): Promise<T> => {
  try {
    let client = apiClientNoIntercep;
    if (useInterceptor) {
      client = apiClient;
    }
    const response: AxiosResponse<T> = await client.post(url, data, {
      headers: {
        ...headers,
        ...getCustomHeaders(),
      },
      withCredentials,
    });
    if (response.status !== 200) {
      throw new Error(response.statusText || "Unknown error occurred");
    }
    const res = response.data;
    return res;
  } catch (error: any) {
    handleError(error);
    // Let the error propagate to be handled by React Query or the component
    throw parseErrorMessage(error);
  }
};

export const getCustomHeaders = () => {
  return {
    Authorization: `Bearer ${tokenManager.getToken()}`,
    user_id: localStorage.getItem("user-email"),
  };
};

export const getRequest = async <T>(url: string, headers?: any): Promise<T> => {
  try {
    const response: AxiosResponse<T> = await apiClient.get(url, {
      headers: {
        ...headers,
        ...getCustomHeaders(),
      },
    });
    if (response.status !== 200) {
      throw parseErrorMessage(response);
    }
    const res = response.data;
    return res;
  } catch (error: any) {
    //handleError(error);
    throw parseErrorMessage(error);
  }
};

